mapper.select:
SELECT a.id, a.project_id AS "projectId", a.stage_id AS "stageId", a.log_date AS "logDate", a.filled_by AS "filledBy", a.current_progress_summary AS "currentProgressSummary", a.expected_completion_at AS "expectedCompletionAt", a.next_day_plan AS "nextDayPlan", a.site_issues AS "siteIssues", a.has_issue AS "hasIssue", a.assistants, a.submitted_at AS "submittedAt", a.attachments, a.status, a.created_by AS "createdBy", a.created_at AS "createdAt", a.updated_by AS "updatedBy", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", s.stage_name AS "stageName", u.name AS "filledByName" FROM construction_log a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN project_stage s ON s.id = a.stage_id LEFT JOIN sys_account u ON u.id = a.filled_by
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.status = #{params.status} AND a.log_date >= #{params.startDate} AND a.log_date <= #{params.endDate}
ORDER BY a.log_date DESC, a.id DESC
